// Replay attack cache
class ReplayProtectionCache {
    private static final Logger LOGGER = Logger.getLogger(ReplayProtectionCache.class.getName());
    private static final long CACHE_CLEANUP_INTERVAL_MS = 60000;
    private static final long MAX_CACHE_ENTRIES = 100000;

    private final ConcurrentHashMap<String, Instant> processedMessageIds = new ConcurrentHashMap<>();
    private volatile long lastCleanupTime = System.currentTimeMillis();

    public boolean isReplay(String messageId, Instant expires) {
        if (messageId == null || messageId.isEmpty()) {
            return true;
        }

        cleanupIfNeeded();

        if (processedMessageIds.size() >= MAX_CACHE_ENTRIES) {
            LOGGER.warning("Replay cache is full, rejecting message for safety");
            return true;
        }

        Instant previous = processedMessageIds.putIfAbsent(messageId, expires);
        if (previous != null) {
            LOGGER.warning("Replay attack detected for message ID: " + sanitizeLogInput(messageId));
            return true;
        }
        return false;
    }

    private void cleanupIfNeeded() {
        long now = System.currentTimeMillis();
        if (now - lastCleanupTime > CACHE_CLEANUP_INTERVAL_MS) {
            lastCleanupTime = now;
            Instant currentTime = Instant.now();
            processedMessageIds.entrySet().removeIf(entry -> entry.getValue().isBefore(currentTime));
        }
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").substring(0, Math.min(input.length(), 100));
    }
}

// WS-Security SOAP Handler
class WsSecurityHandler implements SOAPHandler<SOAPMessageContext> {
    private static final Logger LOGGER = Logger.getLogger(WsSecurityHandler.class.getName());
    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final Duration MAX_TIMESTAMP_AGE = Duration.ofMinutes(5);
    private static final Duration MAX_CLOCK_SKEW = Duration.ofSeconds(30);

    private final ReplayProtectionCache replayCache = new ReplayProtectionCache();

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSS_NS, "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (outbound != null && outbound) {
            return addSecurityHeader(context);
        } else {
            return validateSecurityHeader(context);
        }
    }

    private boolean addSecurityHeader(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            if (header == null) {
                header = envelope.addHeader();
            }

            SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
            securityElement.addAttribute(envelope.createName("mustUnderstand", "soap",
                    "http://schemas.xmlsoap.org/soap/envelope/"), "1");

            SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);
            String messageId = UUID.randomUUID().toString();
            timestampElement.addAttribute(envelope.createName("Id", "wsu", WSU_NS), "TS-" + messageId);

            Instant now = Instant.now();
            Instant expires = now.plus(MAX_TIMESTAMP_AGE);

            SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
            createdElement.addTextNode(now.toString());

            SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(expires.toString());

            message.saveChanges();
            return true;
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Failed to add security header", e);
            return false;
        }
    }

    private boolean validateSecurityHeader(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPHeader header = message.getSOAPHeader();

            if (header == null) {
                LOGGER.warning("Missing SOAP header");
                generateSOAPFault(context, "Missing Security header");
                return false;
            }

            TimestampToken token = extractTimestampToken(header);
            if (token == null) {
                LOGGER.warning("Missing or invalid WS-Security timestamp");
                generateSOAPFault(context, "Missing or invalid WS-Security timestamp");
                return false;
            }

            if (!validateTimestamp(token)) {
                LOGGER.warning("Timestamp validation failed");
                generateSOAPFault(context, "Timestamp validation failed - message expired or too old");
                return false;
            }

            if (replayCache.isReplay(token.getMessageId(), token.getExpires())) {
                LOGGER.warning("Replay attack detected");
                generateSOAPFault(context, "Replay attack detected - message already processed");
                return false;
            }

            return true;
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error validating security header", e);
            generateSOAPFault(context, "Security validation error");
            return false;
        }
    }

    TimestampToken extractTimestampToken(SOAPHeader header) throws SOAPException {
        Iterator<?> securityElements = header.getChildElements(new QName(WSS_NS, "Security"));
        if (!securityElements.hasNext()) {
            return null;
        }

        SOAPElement securityElement = (SOAPElement) securityElements.next();
        Iterator<?> timestampElements = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));
        if (!timestampElements.hasNext()) {
            return null;
        }

        SOAPElement timestampElement = (SOAPElement) timestampElements.next();

        String messageId = timestampElement.getAttributeValue(new QName(WSU_NS, "Id"));
        if (messageId == null || messageId.trim().isEmpty()) {
            messageId = UUID.randomUUID().toString();
        }

        String createdStr = null;
        String expiresStr = null;

        Iterator<?> createdElements = timestampElement.getChildElements(new QName(WSU_NS, "Created"));
        if (createdElements.hasNext()) {
            SOAPElement createdElement = (SOAPElement) createdElements.next();
            createdStr = createdElement.getTextContent();
        }

        Iterator<?> expiresElements = timestampElement.getChildElements(new QName(WSU_NS, "Expires"));
        if (expiresElements.hasNext()) {
            SOAPElement expiresElement = (SOAPElement) expiresElements.next();
            expiresStr = expiresElement.getTextContent();
        }

        if (createdStr == null || expiresStr == null) {
            LOGGER.warning("Missing Created or Expires in Timestamp");
            return null;
        }

        try {
            Instant created = parseTimestamp(createdStr.trim());
            Instant expires = parseTimestamp(expiresStr.trim());

            if (created == null || expires == null) {
                LOGGER.warning("Failed to parse timestamp values");
                return null;
            }

            return new TimestampToken(created, expires, messageId);
        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "Error parsing timestamp", e);
            return null;
        }
    }

    private Instant parseTimestamp(String timestampStr) {
        if (timestampStr == null || timestampStr.isEmpty()) {
            return null;
        }

        // Validate format to prevent injection
        if (timestampStr.length() > 50) {
            LOGGER.warning("Timestamp string too long");
            return null;
        }

        try {
            return Instant.parse(timestampStr);
        } catch (DateTimeParseException e) {
            LOGGER.warning("Invalid timestamp format: " + sanitizeLogInput(timestampStr));
            return null;
        }
    }

    boolean validateTimestamp(TimestampToken token) {
        Instant now = Instant.now();

        // Check if message has expired
        if (now.isAfter(token.getExpires().plus(MAX_CLOCK_SKEW))) {
            LOGGER.warning("Message has expired");
            return false;
        }

        // Check if created timestamp is not in the future (with clock skew allowance)
        if (token.getCreated().isAfter(now.plus(MAX_CLOCK_SKEW))) {
            LOGGER.warning("Message created timestamp is in the future");
            return false;
        }

        // Check if message is not too old
        if (now.isAfter(token.getCreated().plus(MAX_TIMESTAMP_AGE).plus(MAX_CLOCK_SKEW))) {
            LOGGER.warning("Message is too old");
            return false;
        }

        // Check that expires is after created
        if (!token.getExpires().isAfter(token.getCreated())) {
            LOGGER.warning("Expires timestamp is not after Created timestamp");
            return false;
        }

        // Check that the validity window is not unreasonably long
        Duration validity = Duration.between(token.getCreated(), token.getExpires());
        if (validity.compareTo(Duration.ofMinutes(30)) > 0) {
            LOGGER.warning("Timestamp validity window is too long");
            return false;
        }

        return true;
    }

    private void generateSOAPFault(SOAPMessageContext context, String reason) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPBody body = message.getSOAPBody();
            body.removeContents();
            SOAPFault fault = body.addFault();
            fault.setFaultCode(new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
            fault.setFaultString("Security validation failed: " + reason);
            message.saveChanges();
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Failed to generate SOAP fault", e);
        }
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").substring(0, Math.min(input.length(), 100));
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        LOGGER.warning("SOAP fault occurred in security handler");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

// Input validation utility
class InputValidator {
    private static final Pattern TRANSACTION_ID_PATTERN = Pattern.compile("^[a-zA-Z0-9\\-]{1,64}$");
    private static final Pattern MERCHANT_ID_PATTERN = Pattern.compile("^[a-zA-Z0-9\\-]{1,32}$");
    private static final Pattern CURRENCY_PATTERN = Pattern.compile("^[A-Z]{3}$");
    private static final Pattern CARD_MASK_PATTERN = Pattern.compile("^\\*{4}\\d{4}$");
    private static final BigDecimal MAX_AMOUNT = new BigDecimal("999999999.99");
    private static final BigDecimal MIN_AMOUNT = new BigDecimal("0.01");
    private static final int MAX_DESCRIPTION_LENGTH = 256;

    public static String validateTransactionId(String transactionId) {
        if (transactionId == null || !TRANSACTION_ID_PATTERN.matcher(transactionId).matches()) {
            throw new IllegalArgumentException("Invalid transaction ID format");
        }
        return transactionId;
    }

    public static String validateMerchantId(String merchantId) {
        if (merchantId == null || !MERCHANT_ID_PATTERN.matcher(merchantId).matches()) {
            throw new IllegalArgumentException("Invalid merchant ID format");
        }
        return merchantId;
    }

    public static String validateCurrency(String currency) {
        if (currency == null || !CURRENCY_PATTERN.matcher(currency).matches()) {
            throw new IllegalArgumentException("Invalid currency code");
        }
        Set<String> validCurrencies = Set.of("USD", "EUR", "GBP", "JPY", "CAD", "AUD", "CHF");
        if (!validCurrencies.contains(currency)) {
            throw new IllegalArgumentException("Unsupported currency");
        }
        return currency;
    }

    public static BigDecimal validateAmount(BigDecimal amount) {
        if (amount == null) {
            throw new IllegalArgumentException("Amount is required");
        }
        if (amount.compareTo(MIN_AMOUNT) < 0 || amount.compareTo(MAX_AMOUNT) > 0) {
            throw new IllegalArgumentException("Amount out of valid range");
        }
        if (amount.scale() > 2) {
            throw new IllegalArgumentException("Amount cannot have more than 2 decimal places");
        }
        return amount;
    }

    public static String validateCardMask(String cardMask) {
        if (cardMask == null || !CARD_MASK_PATTERN.matcher(cardMask).matches()) {
            throw new IllegalArgumentException("Invalid card mask format");
        }
        return cardMask;
    }

    public static String validateDescription(String description) {
        if (description == null) {
            return "";
        }
        if (description.length() > MAX_DESCRIPTION_LENGTH) {
            throw new IllegalArgumentException("Description too long");
        }
        // Remove any potentially dangerous characters
        return description.replaceAll("[<>&\"']", "");
    }

    public static String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) {
            return "****0000";
        }
        String digitsOnly = cardNumber.replaceAll("[^0-9]", "");
        if (digitsOnly.length() < 4) {
            return "****0000";
        }
        return "****" + digitsOnly.substring(digitsOnly.length() - 4);
    }
}

// Payment Processing Service
@WebService(
        name = "PaymentService",
        serviceName = "PaymentGatewayService",
        portName = "PaymentServicePort",
        targetNamespace = "http://paymentgateway.com/service"
)
public class PaymentProcessingService {
    private static final Logger LOGGER = Logger.getLogger(PaymentProcessingService.class.getName());

    @Resource
    private WebServiceContext wsContext;

    @WebMethod(operationName = "processPayment")
    @WebResult(name = "PaymentResponse")
    public PaymentResponse processPayment(
            @WebParam(name = "transactionId") String transactionId,
            @WebParam(name = "cardNumber") String cardNumber,
            @WebParam(name = "amount") BigDecimal amount,
            @WebParam(name = "currency") String currency,
            @WebParam(name = "merchantId") String merchantId,
            @WebParam(name = "description") String description) {

        PaymentResponse response = new PaymentResponse();
        response.setProcessedAt(Instant.now());

        try {
            // Validate all inputs
            String validatedTxnId = InputValidator.validateTransactionId(transactionId);
            String validatedMerchantId = InputValidator.validateMerchantId(merchantId);
            BigDecimal validatedAmount = InputValidator.validateAmount(amount);
            String validatedCurrency = InputValidator.validateCurrency(currency);
            String maskedCard = InputValidator.maskCardNumber(cardNumber);
            String validatedDescription = InputValidator.validateDescription(description);

            // Build validated payment request
            PaymentRequest request = new PaymentRequest();
            request.setTransactionId(validatedTxnId);
            request.setCardNumberMasked(maskedCard);
            request.setAmount(validatedAmount);
            request.setCurrency(validatedCurrency);
            request.setMerchantId(validatedMerchantId);
            request.setDescription(validatedDescription);

            LOGGER.info("Processing payment: txnId=" + validatedTxnId +
                    ", merchant=" + validatedMerchantId +
                    ", amount=" + validatedAmount + " " + validatedCurrency +
                    ", card=" + maskedCard);

            // Process the payment
            response = executePayment(request);

        } catch (IllegalArgumentException e) {
            LOGGER.warning("Validation error: " + e.getMessage());
            response.setTransactionId(transactionId != null ? transactionId.substring(0, Math.min(transactionId.length(), 64)) : "UNKNOWN");
            response.setStatus("REJECTED");
            response.setMessage("Validation error: " + e.getMessage());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error processing payment", e);
            response.setTransactionId(transactionId != null ? transactionId.substring(0, Math.min(transactionId.length(), 64)) : "UNKNOWN");
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
        }

        return response;
    }

    @WebMethod(operationName = "refundPayment")
    @WebResult(name = "RefundResponse")
    public PaymentResponse refundPayment(
            @WebParam(name = "originalTransactionId") String originalTransactionId,
            @WebParam(name = "refundTransactionId") String refundTransactionId,
            @WebParam(name = "amount") BigDecimal amount,
            @WebParam(name = "merchantId") String merchantId,
            @WebParam(name = "reason") String reason) {

        PaymentResponse response = new PaymentResponse();
        response.setProcessedAt(Instant.now());

        try {
            String validatedOrigTxnId = InputValidator.validateTransactionId(originalTransactionId);
            String validatedRefundTxnId = InputValidator.validateTransactionId(refundTransactionId);
            BigDecimal validatedAmount = InputValidator.validateAmount(amount);
            String validatedMerchantId = InputValidator.validateMerchantId(merchantId);
            String validatedReason = InputValidator.validateDescription(reason);

            LOGGER.info("Processing refund: origTxnId=" + validatedOrigTxnId +
                    ", refundTxnId=" + validatedRefundTxnId +
                    ", merchant=" + validatedMerchantId +
                    ", amount=" + validatedAmount);

            response.setTransactionId(validatedRefundTxnId);
            response.setStatus("REFUNDED");
            response.setMessage("Refund processed for original transaction: " + validatedOrigTxnId);
            response.setAuthorizationCode(generateAuthorizationCode());

        } catch (IllegalArgumentException e) {
            LOGGER.warning("Refund validation error: " + e.getMessage());
            response.setStatus("REJECTED");
            response.setMessage("Validation error: " + e.getMessage());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error processing refund", e);
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
        }

        return response;
    }

    @WebMethod(operationName = "getTransactionStatus")
    @WebResult(name = "StatusResponse")
    public PaymentResponse getTransactionStatus(
            @WebParam(name = "transactionId") String transactionId,
            @WebParam(name = "merchantId") String merchantId) {

        PaymentResponse response = new PaymentResponse();
        response.setProcessedAt(Instant.now());

        try {
            String validatedTxnId = InputValidator.validateTransactionId(transactionId);
            String validatedMerchantId = InputValidator.validateMerchantId(merchantId);

            LOGGER.info("Status inquiry: txnId=" + validatedTxnId + ", merchant=" + validatedMerchantId);

            response.setTransactionId(validatedTxnId);
            response.setStatus("COMPLETED");
            response.setMessage("Transaction found and completed");

        } catch (IllegalArgumentException e) {
            LOGGER.warning("Status inquiry validation error: " + e.getMessage());
            response.setStatus("REJECTED");
            response.setMessage("Validation error: " + e.getMessage());
        }

        return response;
    }

    private PaymentResponse executePayment(PaymentRequest request) {
        PaymentResponse response = new PaymentResponse();
        response.setTransactionId(request.getTransactionId());
        response.setProcessedAt(Instant.now());

        // Simulate payment processing logic
        // In production, this would connect to payment networks
        try {
            // Validate merchant is active
            if (!isMerchantActive(request.getMerchantId())) {
                response.setStatus("DECLINED");
                response.setMessage("Merchant account is not active");
                return response;
            }

            // Check for fraud indicators
            if (isSuspiciousTransaction(request)) {
                response.setStatus("DECLINED");
                response.setMessage("Transaction flagged for review");
                LOGGER.warning("Suspicious transaction flagged: " + request.getTransactionId());
                return response;
            }

            // Process the payment
            String authCode = generateAuthorizationCode();
            response.setStatus("APPROVED");
            response.setMessage("Payment processed successfully");
            response.setAuthorizationCode(authCode);

            LOGGER.info("Payment approved: txnId=" + request.getTransactionId() +
                    ", authCode=" + authCode);

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Payment processing error for txn: " + request.getTransactionId(), e);
            response.setStatus("ERROR");
            response.setMessage("Payment processing failed");
        }

        return response;
    }

    private boolean isMerchantActive(String merchantId) {
        // In production, check against merchant database
        return merchantId != null && !merchantId.isEmpty();
    }

    private boolean isSuspiciousTransaction(PaymentRequest request) {
        // Basic fraud checks - in production, use a proper fraud detection system
        if (request.getAmount().compareTo(new BigDecimal("10000")) > 0) {
            return true;
        }
        return false;
    }

    private String generateAuthorizationCode() {
        // Generate a secure random authorization code
        java.security.SecureRandom random = new java.security.SecureRandom();
        StringBuilder sb = new StringBuilder(8);
        String chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        for (int i = 0; i < 8; i++) {
            sb.append(chars.charAt(random.nextInt(chars.length())));
        }
        return sb.toString();
    }

    // Main method to start the service
    public static void main(String[] args) {
        String address = "http://localhost:8443/payment-gateway/PaymentService";

        PaymentProcessingService service = new PaymentProcessingService();
        Endpoint endpoint = Endpoint.create(service);

        // Add the WS-Security handler
        endpoint.getBinding().setHandlerChain(Collections.singletonList(new WsSecurityHandler()));

        LOGGER.info("Starting Payment Gateway Service at: " + address);
        endpoint.publish(address);
        LOGGER.info("Payment Gateway Service is running.");

        // Add shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down Payment Gateway Service...");
            endpoint.stop();
            LOGGER.info("Payment Gateway Service stopped.");
        }));
    }
}

// SOAP Client helper for testing
class PaymentServiceClient {
    private static final Logger LOGGER = Logger.getLogger(PaymentServiceClient.class.getName());
    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    public static SOAPMessage createPaymentRequest(String transactionId, String cardNumber,
                                                     BigDecimal amount, String currency,
                                                     String merchantId, String description) throws SOAPException {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage message = factory.createMessage();
        SOAPPart soapPart = message.getSOAPPart();
        SOAPEnvelope envelope = soapPart.getEnvelope();

        // Add WS-Security header with timestamp
        SOAPHeader header = envelope.getHeader();
        SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
        securityElement.addAttribute(envelope.createName("mustUnderstand", "soap",
                "http://schemas.xmlsoap.org/soap/envelope/"), "1");

        SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);
        String messageId = UUID.randomUUID().toString();
        timestampElement.addAttribute(envelope.createName("Id", "wsu", WSU_NS), "TS-" + messageId);

        Instant now = Instant.now();
        Instant expires = now.plus(Duration.ofMinutes(5));

        SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
        createdElement.addTextNode(now.toString());

        SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
        expiresElement.addTextNode(expires.toString());

        // Add body
        SOAPBody body = envelope.getBody();
        String serviceNs = "http://paymentgateway.com/service";
        SOAPElement processPayment = body.addChildElement("processPayment", "pay", serviceNs);
        processPayment.addChildElement("transactionId").addTextNode(transactionId);
        processPayment.addChildElement("cardNumber").addTextNode(cardNumber);
        processPayment.addChildElement("amount").addTextNode(amount.toPlainString());
        processPayment.addChildElement("currency").addTextNode(currency);
        processPayment.addChildElement("merchantId").addTextNode(merchantId);
        processPayment.addChildElement("description").addTextNode(description);

        message.saveChanges();
        return message;
    }
}